    gap: 40px;
    align-items: center;
    margin-top: 28px;
  }
  .fly-visual {
    width: 280px;
    height: 280px;
    position: relative;
    flex-shrink: 0;
  }
  .fly-ring {
    position: absolute;
    inset: 0;
    border: 2px solid rgba(99,194,157,0.12);
    border-radius: 50%;
    animation: spin 45s linear infinite;
  }
  .fly-ring2 {
    position: absolute;
    inset: 28px;
    border: 1px dashed rgba(99,194,157,0.06);
    border-radius: 50%;
    animation: spin 65s linear infinite reverse;
  }
  @keyframes spin { to { transform: rotate(360deg); } }
  .fly-ctr {
    position: absolute;
    top: 50%; left: 50%;
    transform: translate(-50%, -50%);
    text-align: center;
    z-index: 2;
  }
