<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Perff AI — Team Slide</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');

  :root {
    --green: #63c29d;
    --green-light: #8cd4b8;
    --green-glow: rgba(99,194,157,0.10);
    --dark: #0b1519;
    --dark2: #0e1e24;
    --dark3: #132c35;
    --text: #b0c8d2;
    --text-light: #d8e6ec;
    --white: #ffffff;
    --text-dim: #587e8c;
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    font-family: 'IBM Plex Sans', sans-serif;
    background: var(--dark);
    color: var(--text);
    font-weight: 300;
    -webkit-font-smoothing: antialiased;
  }

  .slide {
    width: 100vw;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    justify-content: center;
    padding: 60px 80px;
    position: relative;
    overflow: hidden;
  }
  .slide::before {
    content: '';
    position: absolute; inset: 0;
    background:
      radial-gradient(ellipse at 6% 10%, rgba(99,194,157,0.03) 0%, transparent 50%),
      radial-gradient(ellipse at 94% 90%, rgba(99,194,157,0.015) 0%, transparent 50%);
    pointer-events: none;
  }
  .slide-bar {
    position: absolute; top: 0; left: 0; right: 0; height: 2px;
    background: linear-gradient(90deg, var(--green), transparent 55%);
    opacity: 0.2;
  }
  .slide-hdr {
    position: absolute; top: 28px; left: 80px; right: 80px;
    display: flex; justify-content: space-between; align-items: center;
  }
  .s-logo { opacity: 0.3; }
  .s-num {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 11px; color: var(--text-dim); letter-spacing: 2px;
  }

  .kicker {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 11px; color: var(--green); text-transform: uppercase;
    letter-spacing: 4.5px; margin-bottom: 14px; font-weight: 500;
  }
  .h1 {
    font-size: 44px; font-weight: 600; color: var(--white);
    line-height: 1.14; letter-spacing: -1.5px;
  }
  .accent { color: var(--green); }
  .bold { font-weight: 600; color: var(--white); }
  .body {
    font-size: 15px; line-height: 1.7; color: var(--text);
  }

  /* ===== FOUNDERS GRID ===== */
  .founders {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 32px;
    margin-top: 36px;
    max-width: 900px;
  }

  .founder-card {
    background: linear-gradient(145deg, var(--green-glow), var(--dark2));
    border: 1px solid rgba(99,194,157,0.18);
    border-radius: 20px;
    padding: 40px 36px;
    position: relative;
    overflow: hidden;
    text-align: center;
  }
  .founder-card::before {
    content: '';
    position: absolute; top: 0; left: 0; right: 0; height: 3px;
    background: linear-gradient(90deg, var(--green), var(--green-light), transparent);
  }

  .f-avatar {
    width: 96px; height: 96px; border-radius: 50%;
    background: linear-gradient(135deg, #4a9e7d, var(--green));
    display: flex; align-items: center; justify-content: center;
    font-size: 32px; font-weight: 700; color: var(--dark);
    margin: 0 auto 18px;
    border: 3px solid rgba(99,194,157,0.3);
  }

  .f-name {
    font-size: 26px; font-weight: 700; color: var(--white);
    letter-spacing: -0.5px; margin-bottom: 4px;
  }

  .f-role {
    font-size: 15px; font-weight: 500; color: var(--green);
    margin-bottom: 16px;
  }

  .f-tags {
    display: flex; flex-wrap: wrap; gap: 8px;
    justify-content: center; margin-bottom: 24px;
  }
  .f-tag {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 10px; font-weight: 600;
    padding: 4px 12px; border-radius: 6px;
    letter-spacing: 0.5px;
  }
  .f-tag.exit {
    background: rgba(240,199,94,0.1); color: #f0c75e;
    border: 1px solid rgba(240,199,94,0.15);
  }
  .f-tag.exp {
    background: rgba(99,194,157,0.06); color: var(--green);
    border: 1px solid rgba(99,194,157,0.1);
  }

  .f-divider {
    width: 40px; height: 1px;
    background: rgba(99,194,157,0.15);
    margin: 0 auto 20px;
  }

  /* Previous Logos Section */
  .f-logos-label {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 9px; color: var(--text-dim);
    text-transform: uppercase; letter-spacing: 2px;
    margin-bottom: 14px;
  }

  .f-logos {
    display: flex; flex-wrap: wrap; gap: 10px;
    justify-content: center;
  }

  .f-logo {
    background: var(--dark3);
    border: 1px solid rgba(99,194,157,0.06);
    border-radius: 8px;
    padding: 8px 16px;
    font-size: 13px;
    font-weight: 600;
    color: var(--text-dim);
    transition: all 0.2s;
    display: flex;
    align-items: center;
    gap: 6px;
  }
  .f-logo:hover {
    border-color: rgba(99,194,157,0.18);
    color: var(--text-light);
  }
  .f-logo .logo-icon {
    width: 18px; height: 18px; border-radius: 4px;
    display: flex; align-items: center; justify-content: center;
    font-size: 10px; font-weight: 700;
    flex-shrink: 0;
  }

  /* Specific logo brand colors */
  .logo-equiti .logo-icon { background: #0a2e5c; color: #4facfe; }
  .logo-digizag .logo-icon { background: #1a1a2e; color: #e94560; }
  .logo-da .logo-icon { background: #1e3a5f; color: #7ec8e3; }
  .logo-rn .logo-icon { background: #2d132c; color: #ee4c7c; }
  .logo-nana .logo-icon { background: #2d8b3e; color: #fff; }
  .logo-exit .logo-icon { background: #f0c75e; color: #1a1a1a; }
  .logo-mbit .logo-icon { background: #1a3845; color: var(--green); }

  /* ===== TEAM GRID ===== */
  .team-rest-label {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 10px; color: var(--text-dim);
    text-transform: uppercase; letter-spacing: 3px;
    margin-top: 40px; margin-bottom: 16px;
  }

  .team-grid {
    display: grid;
    grid-template-columns: repeat(6, 1fr);
    gap: 12px;
  }

  .tm {
    background: var(--dark2);
    border: 1px solid rgba(99,194,157,0.06);
    border-radius: 12px;
    padding: 18px 14px;
    text-align: center;
    transition: border-color 0.25s;
  }
  .tm:hover { border-color: rgba(99,194,157,0.15); }

  .tm-avatar {
    width: 44px; height: 44px; border-radius: 50%;
    background: var(--dark3); border: 1px solid rgba(99,194,157,0.1);
    display: flex; align-items: center; justify-content: center;
    font-size: 14px; font-weight: 600; color: var(--green);
    margin: 0 auto 8px;
  }
  .tm-name { font-size: 12px; font-weight: 600; color: var(--white); margin-bottom: 2px; }
  .tm-role { font-size: 9px; color: var(--text-dim); line-height: 1.35; }
  .tm-loc { font-size: 8px; color: var(--text-dim); margin-top: 3px; }

  /* ===== STRATEGIC HIRES ===== */
  .hires-label {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 10px; color: var(--green);
    text-transform: uppercase; letter-spacing: 3px;
    margin-top: 32px; margin-bottom: 14px;
  }

  .hires-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 14px;
  }

  .hire {
    background: var(--dark2);
    border: 1px solid rgba(99,194,157,0.07);
    border-radius: 12px;
    padding: 20px;
    text-align: center;
  }
  .hire-val {
    font-size: 28px; font-weight: 700; color: var(--green); margin-bottom: 4px;
  }
  .hire-title { font-size: 13px; font-weight: 600; color: var(--white); margin-bottom: 2px; }
  .hire-body { font-size: 11px; color: var(--text-dim); }

  @media (max-width: 1000px) {
    .slide { padding: 44px 28px; }
    .h1 { font-size: 28px; }
    .founders { grid-template-columns: 1fr; }
    .team-grid { grid-template-columns: repeat(3, 1fr); }
    .hires-grid { grid-template-columns: 1fr; }
    .slide-hdr { left: 28px; right: 28px; }
  }
</style>
</head>
